 minihack/agent/polybeast/evaluate.py  |   3 +-
 minihack/tests/test_envs.py           |   4 +-
 minihack/tiles/tile_test.ipynb        | 178 +++++++++++++++++-----------------
 4 files changed, 94 insertions(+), 93 deletions(-)

diff --git a/minihack/agent/common/envs/wrapper.py b/minihack/agent/common/envs/wrapper.py
index 9b9e2a1..e95bab9 100644
--- a/minihack/agent/common/envs/wrapper.py
+++ b/minihack/agent/common/envs/wrapper.py
@@ -70,7 +70,7 @@ class CropWrapper(gym.Wrapper):
         self.last_observation = None
         self._actions = self.env.actions

-    def render(self, mode="human", crop=True):
+    def render(self, crop=True):
         self.env.render()
         obs = self.last_observation
         tty_chars_crop = obs["tty_chars_crop"]
diff --git a/minihack/agent/polybeast/evaluate.py b/minihack/agent/polybeast/evaluate.py
index 125ce45..4ab7bfd 100644
--- a/minihack/agent/polybeast/evaluate.py
+++ b/minihack/agent/polybeast/evaluate.py
@@ -78,6 +78,7 @@ def eval(
         savedir=savedir,
         max_episode_steps=max_steps,
         observation_keys=obs_keys.split(","),
+        render_mode=render_mode,
     )
     if seeds is not None:
         env.seed(seeds)
@@ -118,7 +119,7 @@ def eval(
             print("Previous reward:", reward)
             if action is not None:
                 print("Previous action: %s" % repr(env.actions[action]))
-            env.render(render_mode)
+            env.render()

         if save_gif:
             obs_image = PIL.Image.fromarray(obs["pixel_crop"])
diff --git a/minihack/tests/test_envs.py b/minihack/tests/test_envs.py
index febf34c..6000e65 100644
--- a/minihack/tests/test_envs.py
+++ b/minihack/tests/test_envs.py
@@ -249,14 +249,14 @@ class TestGymEnvRollout:
         compare_rollouts(env0, env1, rollout_len)

     def test_render_ansi(self, env_name, rollout_len):
-        env = gym.make(env_name)
+        env = gym.make(env_name, render_mode="ansi")
         env.reset()
         for _ in range(rollout_len):
             action = env.action_space.sample()
             _, _, done, _ = env.step(action)
             if done:
                 env.reset()
-            output = env.render(mode="ansi")
+            output = env.render()
             assert isinstance(output, str)
             assert len(output.replace("\n", "")) == np.prod(
                 nle.env.DUNGEON_SHAPE
